select id, name, code, description, status, create_time, update_time, create_user, update_user from role
id = #{id} and name like concat('%',#{name},'%') and code like concat('%',#{code},'%') and description like concat('%',#{description},'%') and status = #{status}
order by create_time asc

select count(*)
from role
where code = #{code}
